var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 아이들이야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきたあの子たちだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that these children, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在你腦海中的個孩子，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 아이들과 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであの子たちとともにいることを。","ENG":"that you'll be with them, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和那個孩子一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called them to your office. They said they'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"오빠! 우리 맛있는 거 주려고 부른 거야? 그치?","JPN":"お兄ちゃん！ぼくたちに美味しいものご馳走してくれるの～？","ENG":"Brother, you called us to give us some snacks, didn't you?","TWN":"哥哥！要給我好吃的東西才叫我們的？對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"오자마자 먹는 거 타령이라니. 츠바이는 대체 오빠를 뭐라고 생각하는 거야?","JPN":"来てすぐに食べ物のことばっか言って。ツヴァイはお兄ちゃんを何だと思ってるの？","ENG":"You're talking about eating again. Zwei, what do you think he is, a food dispenser?","TWN":"只知道吃吃吃，茨粨你到底把哥哥當成什麼了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"야호, 초콜릿이다. 초콜릿!","JPN":"やった、チョコレートだよ、チョコレート！","ENG":"Wee, chocolate! Chocolate!","TWN":"呀比~，巧克力啊，巧克力！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"아앗...... 내 거! 내 거도 있는 거지? ......앗싸!","JPN":"あぁっ……わたしの！わたしの分もあるよね？……やった！","ENG":"Ah! Mine! You've got mine too, don't you? Teehee!","TWN":"啊咦...... 我的！我也有吧？ ......喔耶！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"우물우물...... 꿀꺽-","JPN":"もぐもぐ……ゴックン。","ENG":"*Nom, Nom* *Gulp*","TWN":"咕嚕咕嚕...... 咕嗒-"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"냠~","JPN":"ぱくっ。","ENG":"*Yum*","TWN":"好吃~"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아인! 나 초콜릿 더 먹고 싶어!","JPN":"アイン！ぼく、チョコレートもっと食べたい！","ENG":"Eins, I want more chocolate.","TWN":"艾茵！我還想吃巧克力！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"아앗, 너어! 이건 안돼애! 오빠가 준 거라구! 네 건 벌써 다 먹었잖아.","JPN":"あぁっ、ツヴァイ！これはダメェ！お兄ちゃんにもらったんだから！ツヴァイのはもう食べ終わったでしょ。","ENG":"Ah, no! Not this one! He gave it to me. You ate yours.","TWN":"啊咦！你呀！這個不行啊！這是哥哥給我的！你的不是吃完了嗎。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"히잉.","JPN":"ふえん。","ENG":"Hnnnggg...","TWN":"嗚嗚。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"오빠, 우리 밖에 놀러 가자. 여기만 있으면 답답해~ 응?","JPN":"お兄ちゃん、一緒に遊びに出かけよう。ずっとここにいると退屈だよ～、ね？","ENG":"Brother, can't we go outside? It's boring to stay here. Please?","TWN":"哥哥，我們去外面玩吧，待在這裡覺得很悶~ 嗯?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"으휴, 이 철부지. 오빠는 일하느라 바쁘잖아. 이럴 땐 방해하면 안 되는 거 몰라?","JPN":"もう、子どもなんだから。\\nお兄ちゃんはお仕事で忙しいでしょ。こんなときは邪魔しちゃダメなの。","ENG":"Gosh, stop being so immature. Can't you see he's busy working?","TWN":"哎呦，真不懂事，哥哥在工作很忙呢，像這種時候不知道不能打擾嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"오빠랑 같이 놀려고 온 거 아니었어? 그게 아니면 우린 여기 왜 온 거야?","JPN":"お兄ちゃんと遊びに来たんじゃないの？それじゃなきゃ、ぼくたち何しに来たの？","ENG":"I thought he called us to play with us. Why did he call us, then?","TWN":"不是和哥哥一起來玩的嗎？不是的話我們來這裡幹嘛啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그야 오빠도 다 이유가 있으니 불렀겠지! 그게 뭔진...... 모르겠지만.","JPN":"そりゃお兄ちゃんも理由があるから呼んだんでしょ！それが何かは……知らないけど。","ENG":"He has to have a reason... whatever it is.","TWN":"那是哥哥也有事情才叫我們的吧，雖然...... 不知道那是什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"응? 계약서? 앞으로도 쭉 같이 지내기 위해 필요한 서류라구?","JPN":"うん？契約書？これからもずっと一緒にいられるために必要な書類？","ENG":"Hm? A contract? A document that we need to sign to stay with you?","TWN":"嗯？合約？為了以後一直在一起而需要的文件嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"뭐야. 난 지금까지 당연히 오빠랑 평생 같이 지내는 건 줄 알았는데......?","JPN":"な、何よ。わたしはこれまで、お兄ちゃんとずっと一緒にいられるのは当たり前だと思ってたのに……！","ENG":"I thought we were definitely going to stay with you forever...","TWN":"什麼啊，我到現在還以爲會和哥哥一輩子在一起呢...？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"앗, 아인 얼굴 빨개졌어. 화난 거야?","JPN":"あっ、アインの顔、赤くなっちゃった。怒ってるの？","ENG":"Ah, Eins, your face is red. Are you angry?","TWN":"咦，艾茵臉紅了，生氣啦？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"아, 아니거든! 고작 이런 걸로 내가 삐질 리가 없잖아!","JPN":"ち、違う！こんなことで怒るわけないでしょ！","ENG":"N-no! I don't get angry over something so small!","TWN":"沒、沒有啊！像這麽點小事怎麼會生氣呢！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아인은~ 오빠한테~ 삐졌대요~ 달래주려면 초콜릿 100개는 필요하겠다!","JPN":"アインは～お兄ちゃんに～怒ってま～す！慰めるには、チョコ100個は必要だね！","ENG":"Eins is angry with you, Brother. You'll need tons of chocolate to change her mind.","TWN":"艾茵~ 生哥哥的氣囉~ 要是要安慰的話應該需要 100個巧克力呢！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그건 그냥 네가 먹고 싶을 뿐이잖아!","JPN":"それは、ただツヴァイが食べたいだけでしょ！","ENG":"You're only saying that because you want chocolate!","TWN":"那是因為你想吃而已吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"난...... 오빠랑 같이 있는 것만으로도 충분하다구.","JPN":"わたしは……お兄ちゃんと一緒にいられるだけで充分なの。","ENG":"I... I'm happy so long as I'm with him.","TWN":"我...... 跟哥哥在一起就足夠了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"앗! 나도야! 오빠랑 같이 있기만 해도 하늘 땅만큼 좋아!","JPN":"あっ！ぼくも！お兄ちゃんと一緒にいるだけで、すごく嬉しい！","ENG":"Ah! Me, too! I like just being with you, Brother.","TWN":"咦！我也是！只要跟哥哥在一起比什麼都好！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"그치만 같이 산책해주고 맛있는 것도 주는 오빠라서 우주 은하만큼 더 좋아! 히히~","JPN":"それに、一緒にお散歩もしてくれるし、美味しいものもくれるお兄ちゃんだから大大好き！へへ～。","ENG":"But I like it more when you take walks with us and give us delicious snacks. Teehee!","TWN":"可是陪我散步買給我好吃的也是哥哥，我比宇宙還要喜歡哥哥！嘿嘿~"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"츠바이도 참~ 못 말린다니까.","JPN":"もう、ツヴァイったら、しょうがないわね。","ENG":"Zwei, you're helpless.","TWN":"茨粨你真~ 受不了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};